以下是抓取微信文章正文内容的完整解决方案，包含结构化保存和格式优化功能：

```python
import requests
from bs4 import BeautifulSoup, Tag
import re
from typing import List, Dict

class WechatArticleScraper:
    def __init__(self):
        self.headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/119.0.0.0 Safari/537.36'
        }
        self.clean_regex = re.compile(r'[\x00-\x1F\x7F\u200b\u202e]')

    def scrape_article(self, url: str) -> Dict:
        """主抓取方法"""
        try:
            response = requests.get(url, headers=self.headers, timeout=15)
            response.encoding = 'utf-8'
            soup = BeautifulSoup(response.text, 'lxml')

            return {
                'title': self._get_title(soup),
                'subtitles': self._get_subtitles(soup),
                'content': self._get_structured_content(soup),
                'metadata': self._get_metadata(soup)
            }
        except Exception as e:
            return {'error': str(e)}

    def _get_title(self, soup) -> str:
        """提取主标题"""
        title_tag = soup.find('h1', class_='rich_media_title')
        return self._clean_text(title_tag.text) if title_tag else ''

    def _get_subtitles(self, soup) -> Dict:
        """提取子标题（复用之前版本）"""
        # 此处可集成之前的子标题提取逻辑
        return {}

    def _get_structured_content(self, soup) -> List[Dict]:
        """结构化正文内容提取"""
        content = []
        js_content = soup.find('div', id='js_content')

        if not js_content:
            return content

        # 智能段落检测
        current_section = {'type': 'paragraph', 'content': []}
        for element in js_content.children:
            if not isinstance(element, Tag):
                continue

            # 处理图片
            if element.name == 'img':
                if current_section['content']:
                    content.append(current_section)
                    current_section = {'type': 'paragraph', 'content': []}
                content.append({
                    'type': 'image',
                    'src': element.get('data-src') or element.get('src'),
                    'alt': self._clean_text(element.get('alt', ''))
                })
                continue

            # 处理列表
            if element.name in ['ul', 'ol']:
                list_type = 'ordered' if element.name == 'ol' else 'unordered'
                items = [self._clean_text(li.text) for li in element.find_all('li')]
                content.append({'type': 'list', 'list_type': list_type, 'items': items})
                continue

            # 处理段落
            text = self._process_text_element(element)
            if text:
                # 检测是否为小标题
                if self._is_heading(element):
                    content.append({'type': 'heading', 'level': self._get_heading_level(element), 'text': text})
                else:
                    current_section['content'].append(text)

        if current_section['content']:
            content.append(current_section)

        return content

    def _process_text_element(self, element: Tag) -> str:
        """处理文本元素"""
        text = element.get_text('\n', strip=True)
        text = self._clean_text(text)

        # 过滤干扰内容
        if any(keyword in text for keyword in ['推荐阅读', '往期精选', '广告声明']):
            return ''
        if re.match(r'^(阅读|点赞)\s*\d+$', text):
            return ''

        return text

    def _is_heading(self, element: Tag) -> bool:
        """判断是否为标题元素"""
        if element.name in ['h2', 'h3', 'h4']:
            return True
        if element.find_parent(['h2', 'h3', 'h4']):
            return True
        return re.match(r'^【.+】|第[一二三四五六七八九十]+章', element.text)

    def _get_heading_level(self, element: Tag) -> int:
        """获取标题层级"""
        if element.name == 'h2': return 2
        if element.name == 'h3': return 3
        if element.name == 'h4': return 4
        return 2  # 默认层级

    def _clean_text(self, text: str) -> str:
        """深度清理文本"""
        text = self.clean_regex.sub('', text)
        text = re.sub(r'\s+', ' ', text)
        text = re.sub(r'[\ue000-\uf8ff]', '', text)  # 移除微信特殊字符
        return text.strip()

    def _get_metadata(self, soup) -> Dict:
        """获取元数据"""
        return {
            'publish_time': self._get_publish_time(soup),
            'author': self._get_author(soup),
            'copyright': self._get_copyright(soup)
        }

    def _get_publish_time(self, soup) -> str:
        """提取发布时间"""
        time_tag = soup.find('em', class_='rich_media_meta rich_media_meta_text')
        return time_tag.text if time_tag else ''

    def _get_author(self, soup) -> str:
        """提取作者"""
        author_tag = soup.find('meta', property='og:author')
        return author_tag.get('content') if author_tag else ''

    def _get_copyright(self, soup) -> str:
        """获取版权声明"""
        copyright_tag = soup.find('span', class_='rich_media_meta rich_media_meta_copyright')
        return copyright_tag.text if copyright_tag else ''

# 使用示例
if __name__ == "__main__":
    scraper = WechatArticleScraper()
    article = scraper.scrape_article("https://mp.weixin.qq.com/s/xxxxxx")

    if 'error' in article:
        print(f"抓取失败：{article['error']}")
    else:
        print(f"标题：{article['title']}")
        print(f"发布时间：{article['metadata']['publish_time']}")
        print("\n正文内容：")
        for item in article['content']:
            if item['type'] == 'image':
                print(f"[图片] {item['alt']}")
            elif item['type'] == 'list':
                print("列表：")
                for i, li in enumerate(item['items'], 1):
                    prefix = f"{i}." if item['list_type'] == 'ordered' else "•"
                    print(f"  {prefix} {li}")
            elif item['type'] == 'heading':
                print(f"\n{item['text']}")
            else:
                print('\n'.join(item['content']))
```

