**增强保存方案：**

1. **保存为Markdown文件：**
```python
def save_as_markdown(article, filename):
    with open(filename, 'w', encoding='utf-8') as f:
        f.write(f"# {article['title']}\n\n")

        for item in article['content']:
            if item['type'] == 'heading':
                f.write(f"\n{'#' * item['level']} {item['text']}\n\n")
            elif item['type'] == 'paragraph':
                f.write('\n'.join(item['content']) + '\n\n')
            elif item['type'] == 'image':
                f.write(f"![{item['alt']}]({item['src']})\n\n")
            elif item['type'] == 'list':
                for i, li in enumerate(item['items'], 1):
                    prefix = f"{i}." if item['list_type'] == 'ordered' else "-"
                    f.write(f"{prefix} {li}\n")
                f.write('\n')
```

2. **保存为Word文档：**
```python
from docx import Document
from docx.shared import Inches

def save_as_word(article, filename):
    doc = Document()
    doc.add_heading(article['title'], level=1)

    for item in article['content']:
        if item['type'] == 'heading':
            doc.add_heading(item['text'], level=item['level'])
        elif item['type'] == 'paragraph':
            doc.add_paragraph('\n'.join(item['content']))
        elif item['type'] == 'image':
            # 需要先下载图片
            doc.add_picture('local_image.jpg', width=Inches(5))
        elif item['type'] == 'list':
            list_style = 'List Number' if item['list_type'] == 'ordered' else 'List Bullet'
            for li in item['items']:
                doc.add_paragraph(li, style=list_style)

    doc.save(filename)
```

