def handle_pagination(soup):
    # 检测分页导航
    page_nav = soup.find('div', class_='page_nav')
    if page_nav:
        page_links = [a['href'] for a in page_nav.find_all('a')]
        return [scrape_article(link) for link in page_links]
    return None
```

