def detect_special_blocks(element):
    # 检测代码块
    if element.find('code'):
        return {'type': 'code', 'language': 'python', 'content': element.text}
    # 检测数学公式
    if element.find('math'):
        return {'type': 'formula', 'content': element.text}
    return None
