def extract_tables(js_content):
    tables = []
    for table in js_content.find_all('table'):
        rows = []
        for tr in table.find_all('tr'):
            cells = [self._clean_text(td.text) for td in tr.find_all(['td', 'th'])]
            rows.append(cells)
        tables.append({'type': 'table', 'data': rows})
    return tables
```

